// Extract error data from webhook payload
const errorData = $input.all()[0].json;

// Validate required fields
const requiredFields = ['client_id', 'workflow_id', 'error_type', 'error_message', 'error_severity', 'error_category'];
const missingFields = requiredFields.filter(field => !errorData[field]);

if (missingFields.length > 0) {
  return [{
    json: {
      success: false,
      error: `Missing required fields: ${missingFields.join(', ')}`
    }
  }];
}

// Determine error severity
const severity = errorData.error_severity.toLowerCase();
const category = errorData.error_category.toLowerCase();

// Create error record
const errorRecord = {
  client_id: parseInt(errorData.client_id),
  workflow_id: errorData.workflow_id,
  execution_id: errorData.execution_id || null,
  error_type: errorData.error_type,
  error_message: errorData.error_message,
  error_stack: errorData.error_stack || null,
  error_severity: ['critical', 'high', 'medium', 'low'].includes(severity) ? severity : 'medium',
  error_category: ['validation', 'network', 'api', 'database', 'system', 'business', 'other'].includes(category) ? category : 'other',
  context: errorData.context ? JSON.stringify(errorData.context) : '{}',
  occurred_at: new Date().toISOString(),
  resolved: false,
  resolved_at: null,
  resolution_notes: null
};

return [{ json: errorRecord }];

// Create alert for critical/high severity errors
const error = $input.all()[0].json;

const alert = {
  client_id: error.client_id,
  alert_type: 'critical_error',
  alert_severity: error.error_severity,
  alert_title: `Critical Error in ${error.workflow_id}`,
  alert_message: `${error.error_type}: ${error.error_message}`,
  source_workflow: error.workflow_id,
  source_entity_type: 'error',
  source_entity_id: error.id,
  metadata: JSON.stringify({
    error_id: error.id,
    error_type: error.error_type,
    error_category: error.error_category,
    occurred_at: error.occurred_at
  }),
  triggered_at: new Date().toISOString(),
  acknowledged: false,
  acknowledged_by: null,
  acknowledged_at: null,
  notification_channels: JSON.stringify(['email', 'slack'])
};

return [{ json: alert }];
